```c
/*
 * ehr_auth.h - Secure Authentication Module for Patient-Facing EHR Portal
 * 
 * HIPAA Security Rule Compliance Considerations:
 *   - §164.312(a)(1): Unique user identification
 *   - §164.312(a)(2)(i): Automatic logoff
 *   - §164.312(d): Person or entity authentication
 *   - §164.312(a)(2)(iii): Emergency access procedure
 *   - §164.308(a)(5)(ii)(C): Login monitoring / failed login attempts
 *
 * Dependencies: OpenSSL (libssl, libcrypto), libsodium, pthreads
 * Compile: gcc -o ehr_auth ehr_auth.c -lssl -lcrypto -lsodium -lpthread -lsqlite3
 */

#ifndef EHR_AUTH_H
#define EHR_AUTH_H

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <errno.h>
#include <pthread.h>
#include <stdbool.h>
#include <ctype.h>
#include <unistd.h>

/* OpenSSL for TLS and cryptographic operations */
#include <openssl/evp.h>
#include <openssl/rand.h>
#include <openssl/sha.h>

/* libsodium for Argon2id password hashing and secure memory */
#include <sodium.h>

/* SQLite for demonstration; replace with your production DB connector */
#include <sqlite3.h>

/* ========================== CONFIGURATION ========================== */

/* Maximum and minimum lengths for user inputs */
#define MAX_USERNAME_LEN        64
#define MIN_USERNAME_LEN        3
#define MAX_PASSWORD_LEN        128
#define MIN_PASSWORD_LEN        12    /* NIST SP 800-63B recommends >= 8; we enforce 12 for PHI */
#define MAX_MFA_CODE_LEN        8
#define MFA_CODE_LEN            6     /* Standard TOTP length */

/* Session configuration */
#define SESSION_TOKEN_BYTES     32    /* 256-bit session tokens */
#define SESSION_TOKEN_HEX_LEN  (SESSION_TOKEN_BYTES * 2 + 1)
#define SESSION_TIMEOUT_SECS    900   /* 15-minute auto-logoff per HIPAA recommendation */
#define MAX_ACTIVE_SESSIONS     1000

/* Account lockout policy */
#define MAX_FAILED_ATTEMPTS     5
#define LOCKOUT_DURATION_SECS   1800  /* 30-minute lockout after max failed attempts */

/* Audit log settings */
#define AUDIT_LOG_PATH          "/var/log/ehr/auth_audit.log"

/* Password hash output size (Argon2id via libsodium) */
#define PASSWORD_HASH_LEN       crypto_pwhash_STRBYTES

/* Rate limiting */
#define RATE_LIMIT_WINDOW_SECS  60
#define RATE_LIMIT_MAX_ATTEMPTS 10

/* ========================== DATA STRUCTURES ========================== */

/* Authentication result codes */
typedef enum {
    AUTH_SUCCESS                = 0,
    AUTH_FAIL_INVALID_CREDS    = 1,
    AUTH_FAIL_ACCOUNT_LOCKED   = 2,
    AUTH_FAIL_MFA_REQUIRED     = 3,
    AUTH_FAIL_MFA_INVALID      = 4,
    AUTH_FAIL_SESSION_EXPIRED  = 5,
    AUTH_FAIL_RATE_LIMITED     = 6,
    AUTH_FAIL_INPUT_INVALID    = 7,
    AUTH_FAIL_INTERNAL_ERROR   = 8,
    AUTH_FAIL_PASSWORD_EXPIRED = 9,
    AUTH_FAIL_ACCOUNT_DISABLED = 10
} AuthResult;

/* User account status */
typedef enum {
    ACCOUNT_ACTIVE             = 0,
    ACCOUNT_LOCKED             = 1,
    ACCOUNT_DISABLED           = 2,
    ACCOUNT_PASSWORD_EXPIRED   = 3
} AccountStatus;

/* Audit event types */
typedef enum {
    AUDIT_LOGIN_SUCCESS        = 0,
    AUDIT_LOGIN_FAILURE        = 1,
    AUDIT_LOGOUT               = 2,
    AUDIT_ACCOUNT_LOCKED       = 3,
    AUDIT_ACCOUNT_UNLOCKED     = 4,
    AUDIT_PASSWORD_CHANGED     = 5,
    AUDIT_MFA_SUCCESS          = 6,
    AUDIT_MFA_FAILURE          = 7,
    AUDIT_SESSION_EXPIRED      = 8,
    AUDIT_RATE_LIMITED         = 9
} AuditEventType;

/* User record (loaded from database) */
typedef struct {
    int         user_id;
    char        username[MAX_USERNAME_LEN + 1];
    char        password_hash[PASSWORD_HASH_LEN];
    char        mfa_secret[65];          /* Base32-encoded TOTP secret */
    bool        mfa_enabled;
    int         failed_attempts;
    time_t      lockout_until;
    time_t      password_last_changed;
    int         password_max_age_days;   /* 0 = no expiry */
    AccountStatus status;
} UserRecord;

/* Active session */
typedef struct {
    char        token[SESSION_TOKEN_HEX_LEN];
    int         user_id;
    char        username[MAX_USERNAME_LEN + 1];
    time_t      created_at;
    time_t      last_activity;
    char        ip_address[46];          /* IPv4 or IPv6 */
    bool        mfa_verified;
    bool        active;
} Session;

/* Rate limit entry */
typedef struct {
    char        ip_address[46];
    int         attempt_count;
    time_t      window_start;
} RateLimitEntry;

/* ========================== GLOBAL STATE ========================== */

static Session          g_sessions[MAX_ACTIVE_SESSIONS];
static pthread_mutex_t  g_session_mutex = PTHREAD_MUTEX_INITIALIZER;
static sqlite3         *g_db = NULL;
static FILE            *g_audit_log = NULL;
static pthread_mutex_t  g_audit_mutex = PTHREAD_MUTEX_INITIALIZER;

/* Simple rate limit table (in production, use Redis or similar) */
#define RATE_LIMIT_TABLE_SIZE 256
static RateLimitEntry   g_rate_limits[RATE_LIMIT_TABLE_SIZE];
static pthread_mutex_t  g_rate_mutex = PTHREAD_MUTEX_INITIALIZER;

/* ========================== UTILITY FUNCTIONS ========================== */

/**
 * Securely zero memory to prevent sensitive data from lingering.
 * Uses sodium_memzero which resists compiler optimization removal.
 */
static void secure_zero(void *ptr, size_t len) {
    if (ptr && len > 0) {
        sodium_memzero(ptr, len);
    }
}

/**
 * Constant-time string comparison to prevent timing attacks.
 */
static bool secure_compare(const char *a, const char *b, size_t len) {
    return sodium_memcmp(a, b, len) == 0;
}

/**
 * Validate that a string contains only allowed characters (alphanumeric + limited special).
 * Prevents injection attacks in usernames.
 */
static bool validate_username_chars(const char *username) {
    if (!username) return false;
    size_t len = strnlen(username, MAX_USERNAME_LEN + 1);
    if (len < MIN_USERNAME_LEN || len > MAX_USERNAME_LEN) return false;

    for (size_t i = 0; i < len; i++) {
        char c = username[i];
        /* Allow alphanumeric, dots, hyphens, underscores only */
        if (!isalnum((unsigned char)c) && c != '.' && c != '-' && c != '_') {
            return false;
        }
    }
    return true;
}

/**
 * Validate password meets complexity requirements.
 * NIST SP 800-63B: Check length, allow all printable characters.
 * Additional: require mixed character classes for PHI systems.
 */
static bool validate_password_complexity(const char *password) {
    if (!password) return false;
    size_t len = strnlen(password, MAX_PASSWORD_LEN + 1);
    if (len < MIN_PASSWORD_LEN || len > MAX_PASSWORD_LEN) return false;

    bool has_upper = false, has_lower = false;
    bool has_digit = false, has_special = false;

    for (size_t i = 0; i < len; i++) {
        unsigned char c = (unsigned char)password[i];
        /* Reject non-printable characters */
        if (c < 0x20 || c > 0x7E) return false;

        if (isupper(c))      has_upper = true;
        else if (islower(c)) has_lower = true;
        else if (isdigit(c)) has_digit = true;
        else                 has_special = true;
    }

    /* Require at least 3 of 4 character classes */
    int classes = has_upper + has_lower + has_digit + has_special;
    return classes >= 3;
}

/**
 * Generate a cryptographically secure random hex token.
 */
static bool generate_secure_token(char *hex_out, size_t hex_out_size, size_t num_bytes) {
    if (hex_out_size < (num_bytes * 2 + 1)) return false;

    unsigned char *buf = sodium_malloc(num_bytes);
    if (!buf) return false;

    randombytes_buf(buf, num_bytes);

    /* Convert to hex string */
    sodium_bin2hex(hex_out, hex_out_size, buf, num_bytes);

    sodium_free(buf);
    return true;
}

/**
 * Get current UTC time as a formatted string for audit logs.
 */
static void get_timestamp_str(char *buf, size_t buf_size) {
    time_t now = time(NULL);
    struct tm utc;
    gmtime_r(&now, &utc);
    strftime(buf, buf_size, "%Y-%m-%dT%H:%M:%SZ", &utc);
}

/* ========================== AUDIT LOGGING ========================== */

/**
 * Write an audit log entry. HIPAA §164.312(b) requires audit controls.
 * All authentication events must be logged with:
 *   - Timestamp (UTC)
 *   - Event type
 *   - Username (or attempted username)
 *   - Source IP
 *   - Success/failure
 *   - Additional details
 */
static void audit_log(AuditEventType event, const char *username,
                       const char *ip_address, const char *details) {
    if (!g_audit_log) return;

    char timestamp[32];
    get_timestamp_str(timestamp, sizeof(timestamp));

    const char *event_names[] = {
        "LOGIN_SUCCESS", "LOGIN_FAILURE", "LOGOUT",
        "ACCOUNT_LOCKED", "ACCOUNT_UNLOCKED", "PASSWORD_CHANGED",
        "MFA_SUCCESS", "MFA_FAILURE", "SESSION_EXPIRED", "RATE_LIMITED"
    };

    const char *event_name = (event <= AUDIT_RATE_LIMITED) ?
                              event_names[event] : "UNKNOWN";

    pthread_mutex_lock(&g_audit_mutex);
    fprintf(g_audit_log, "[%s] EVENT=%s USER=\"%s\" IP=%s DETAILS=\"%s\"\n",
            timestamp,
            event_name,
            username ? username : "N/A",
            ip_address ? ip_address : "N/A",
            details ? details : "");
    fflush(g_audit_log);
    pthread_mutex_unlock(&g_audit_mutex);
}

/* ========================== RATE LIMITING ========================== */

/**
 * Check if an IP address has exceeded the rate limit.
 * Simple in-memory implementation; use Redis in production.
 */
static bool is_rate_limited(const char *ip_address) {
    if (!ip_address) return true;

    time_t now = time(NULL);
    pthread_mutex_lock(&g_rate_mutex);

    /* Find existing entry or empty slot */
    int target = -1;
    unsigned long hash = 5381;
    for (const char *p = ip_address; *p; p++) {
        hash = ((hash << 5) + hash) + (unsigned char)*p;
    }
    target = (int)(hash % RATE_LIMIT_TABLE_SIZE);

    RateLimitEntry *entry = &g_rate_limits[target];

    /* Reset if window has expired */
    if (now - entry->window_start > RATE_LIMIT_WINDOW_SECS) {
        memset(entry, 0, sizeof(RateLimitEntry));
        strncpy(entry->ip_address, ip_address, sizeof(entry->ip_address) - 1);
        entry->window_start = now;
    }

    /* Check if same IP (hash collision handling is simplified here) */
    if (strncmp(entry->ip_address, ip_address, sizeof(entry->ip_address)) == 0) {
        entry->attempt_count++;
        bool limited = entry->attempt_count > RATE_LIMIT_MAX_ATTEMPTS;
        pthread_mutex_unlock(&g_rate_mutex);
        return limited;
    }

    pthread_mutex_unlock(&g_rate_mutex);
    return false;
}

/* ========================== DATABASE OPERATIONS ========================== */

/**
 * Initialize the database connection and create tables if needed.
 * In production, use a hardened PostgreSQL/MySQL with TLS and parameterized queries.
 */
static bool db_initialize(const char *db_path) {
    int rc = sqlite3_open(db_path, &g_db);
    if (rc != SQLITE_OK) {
        fprintf(stderr, "ERROR: Cannot open database: %s\n", sqlite3_errmsg(g_db));
        return false;
    }

    /* Enable WAL mode for better concurrency */
    sqlite3_exec(g_db, "PRAGMA journal_mode=WAL;", NULL, NULL, NULL);

    /* Create users table */
    const char *create_sql =
        "CREATE TABLE IF NOT EXISTS users ("
        "  user_id INTEGER PRIMARY KEY AUTOINCREMENT,"
        "  username TEXT UNIQUE NOT NULL,"
        "  password_hash TEXT NOT NULL,"
        "  mfa_secret TEXT DEFAULT '',"
        "  mfa_enabled INTEGER DEFAULT 0,"
        "  failed_attempts INTEGER DEFAULT 0,"
        "  lockout_until INTEGER DEFAULT 0,"
        "  password_last_changed INTEGER DEFAULT 0,"

